}

// recvAck reads the kernel's NLMSG_ERROR acknowledgement for the request just sent
// on fd. A zero error code is the success ACK (NLM_F_ACK). A non-zero code is
// returned as the corresponding unix.Errno.
func recvAck(fd int) error {
	buf := make([]byte, unix.Getpagesize())
	n, _, err := unix.Recvfrom(fd, buf, 0)
	if err != nil {
		return fmt.Errorf("recv rtnetlink ack: %w", err)
	}
	msgs, err := unix.ParseNetlinkMessage(buf[:n])
	if err != nil {
		return fmt.Errorf("parse rtnetlink ack: %w", err)
	}
	for _, m := range msgs {
		if m.Header.Type == unix.NLMSG_ERROR {
			// struct nlmsgerr: the leading int32 is the negated errno (0 on success).
			code := int32(binary.NativeEndian.Uint32(m.Data[0:4]))
			if code == 0 {
				return nil
			}
			return unix.Errno(-code)
		}
	}
